(183, 622, 1, NULL, 'Beef Cutting Project', NULL, 0, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Bachok is one of the district from kelantan that have beautiful nature. The beaches and beauty scenery are common if you come to Bachok. The main source of economic are agriculture. Besides farming, the locals are actively breeding the livestock. The different types of  cows  and goats are part of the daily lives here in Bachok. The locals are selling the fresh beef by the roadside. However, none of them sell the beef that have different cut for steak, barbecue, steamboat from a different cut. The main objective for this project is to empower the local people in beef supply with different cut for different purpose.', 1, NULL, NULL, NULL, NULL, 0, 1717830603, 1717830603, NULL),
(184, 609, 2, 1, 'Athyrose Textile', NULL, 10, 'EP60', 'K1', NULL, 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 73.34, 60, 0, 1717830622, 1717901547, '2024-06-09 10:52:08'),
(185, 623, 1, NULL, 'FOOD SECURITY - CLUSTER CHICKEN PROJECT', NULL, 10, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'In 2019, Bachok had been listed as the poorest area in Peninsular Malaysia. In 2023, the government introduced Inisiatif Pendapatan Rakyat (IPR) to improve the economic and social condition of the poor area. Even though Bachok is one of the poorest area, it is rich with the natural resources such as beautiful beaches, Gelam tree forest, hills and fields.\r\n	Therefore, it is very common to see the livestock and agricultural activities initiated in the area. This project is introducing CLUSTER CHICKEN PROJECT to help the local people to improve their standard of living\r\n	The main objective is to provide a quality chicken with cheaper price to the locals', 1, NULL, NULL, NULL, NULL, 0, 1717830782, 1717830782, '2024-06-08 15:13:02'),
(186, 546, 2, 1, 'LPH GLOBAL ENTERPRISE (Little Penang Hawker)', NULL, 10, 'EP 52', '', NULL, 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 82.78, 80, 0, 1717831223, 1717831223, '2024-06-08 15:20:23'),
(187, 625, 1, NULL, 'E-KUBUR:Empowering GIS Technology in Community Management', NULL, 10, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'This project focus on \r\nDigitalizing conventional \r\ngrave management data to \r\nenhance efficiency and \r\norganization using GIS \r\ntechnology.', 1, NULL, NULL, 50.00, 10, 0, 1717831525, 1717942568, '2024-06-09 22:16:08'),
